import type { ChatMessage, MessageGrouping } from '../../model/use-chat-session';
import { useAppStore } from '@/layers/shared/model';
import { cn } from '@/layers/shared/lib';
import { messageItem } from './message-variants';
import { MessageProvider } from './MessageContext';
import { UserMessageContent } from './UserMessageContent';
import { AssistantMessageContent } from './AssistantMessageContent';
import type { InteractiveToolHandle } from './types';

interface MessageItemProps {
  message: ChatMessage;
  grouping: MessageGrouping;
  sessionId: string;
  isNew?: boolean;
  isStreaming?: boolean;
  activeToolCallId?: string | null;
  onToolRef?: (handle: InteractiveToolHandle | null) => void;
  focusedOptionIndex?: number;
  onToolDecided?: (toolCallId: string) => void;
}

/** Format a timestamp string to a short time display (HH:MM). */
function formatTime(timestamp: string): string {
  try {
    return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

/**
 * Message item orchestrator — reads grouping, role, and store settings,
 * then delegates rendering to UserMessageContent or AssistantMessageContent.
 * Provides MessageContext to all children for prop drilling elimination.
 */
export function MessageItem({
  message,
  grouping,
  sessionId,
  isNew = false,
  isStreaming = false,
  activeToolCallId = null,
  onToolRef,
  focusedOptionIndex = -1,
  onToolDecided,
}: MessageItemProps) {
  const isUser = message.role === 'user';
  const { showTimestamps } = useAppStore();
  const { position, groupIndex } = grouping;
  const showIndicator = position === 'only' || position === 'first';
  const isGroupStart = position === 'only' || position === 'first';

  const styles = messageItem({
    role: isUser ? 'user' : 'assistant',
    position,
  });

  return (
    <MessageProvider
      value={{ sessionId, isStreaming, activeToolCallId, onToolRef, focusedOptionIndex, onToolDecided }}
    >
      <motion.div
        initial={isNew ? { opacity: 0, y: 8, scale: isUser ? 0.97 : 1 } : false}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ type: 'spring', stiffness: 320, damping: 28 }}
        data-testid="message-item"
        data-role={message.role}
        className={styles.root()}
      >
        {isGroupStart && groupIndex > 0 && <div className={styles.divider()} />}
        {message.timestamp && (
          <span
            className={cn(
              styles.timestamp(),
              showTimestamps
                ? 'text-muted-foreground/60'
                : 'text-muted-foreground/0 group-hover:text-muted-foreground/60'
            )}
          >
            {formatTime(message.timestamp)}
          </span>
        )}
        <div className={styles.leading()}>
          {showIndicator &&
            (isUser ? (
              <ChevronRight className="text-muted-foreground size-(--size-icon-md)" />
            ) : (
              <span className="text-muted-foreground flex size-(--size-icon-md) items-center justify-center text-[10px]">
                ●
              </span>
            ))}
        </div>
        <div className={styles.content()}>
          {isUser ? (
            <UserMessageContent message={message} />
          ) : (
            <AssistantMessageContent message={message} />
          )}
        </div>
      </motion.div>
    </MessageProvider>
  );
}
```

Key differences from the original:
- **Styling**: Uses `messageItem()` TV call instead of inline `cn()` conditionals. The TV slot functions (`styles.root()`, `styles.content()`, etc.) replace the manual class string building.
- **Rendering**: Delegates to `UserMessageContent` and `AssistantMessageContent` instead of inlining all rendering logic.
- **Context**: Wraps children in `MessageProvider` so sub-components can access `sessionId`, `isStreaming`, etc. via `useMessageContext()`.
- **Props**: The `MessageItemProps` interface is identical to the original — no external API change.

